class Solution:
    def minimumOperationsToWriteY(self, grid):
        n = len(grid)
        mid = n // 2
        y_cells = set()
        for i in range(mid + 1):
            y_cells.add((i, i))
            y_cells.add((i, n - 1 - i))
        for i in range(mid, n):
            y_cells.add((i, mid))
        y_count = [0, 0, 0]
        bg_count = [0, 0, 0]
        for r in range(n):
            for c in range(n):
                if (r, c) in y_cells:
                    y_count[grid[r][c]] += 1
                else:
                    bg_count[grid[r][c]] += 1
        total_y = sum(y_count)
        total_bg = sum(bg_count)
        best = float('inf')
        for yv in range(3):
            for bv in range(3):
                if yv == bv:
                    continue
                cost = (total_y - y_count[yv]) + (total_bg - bg_count[bv])
                best = min(best, cost)
        return best

