var minimumOperationsToWriteY = function(grid) {
    const n = grid.length;
    const mid = Math.floor(n / 2);
    const yCells = new Set();
    for (let i = 0; i <= mid; i++) {
        yCells.add(i * n + i);
        yCells.add(i * n + (n - 1 - i));
    }
    for (let i = mid; i < n; i++) {
        yCells.add(i * n + mid);
    }
    const yCount = [0, 0, 0], bgCount = [0, 0, 0];
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < n; c++) {
            if (yCells.has(r * n + c)) yCount[grid[r][c]]++;
            else bgCount[grid[r][c]]++;
        }
    }
    const totalY = yCount[0]+yCount[1]+yCount[2];
    const totalBg = bgCount[0]+bgCount[1]+bgCount[2];
    let best = Infinity;
    for (let yv = 0; yv < 3; yv++) {
        for (let bv = 0; bv < 3; bv++) {
            if (yv === bv) continue;
            const cost = (totalY - yCount[yv]) + (totalBg - bgCount[bv]);
            if (cost < best) best = cost;
        }
    }
    return best;
};
